mapper.select:
SELECT wr.user_id, u.real_name, wr.category_id, wc.category_name, COUNT(wr.id) AS totalCount, SUM(wre.amount) AS totalAmount FROM work_record wr JOIN user u ON wr.user_id = u.id LEFT JOIN work_category wc ON wr.category_id = wc.id LEFT JOIN work_record_expense wre ON wr.id = wre.work_record_id
wr.deleted = 0 AND wr.user_id = #{userId} AND wr.create_time >= #{endTimeFrom} AND wr.create_time <= #{endTimeTo}
GROUP BY wr.user_id, u.real_name, wr.category_id, wc.category_name ORDER BY wr.user_id, totalCount DESC

SELECT wc.category_name, COUNT(wr.id) AS totalCount FROM work_record wr LEFT JOIN work_category wc ON wr.category_id = wc.id
wr.deleted = 0 AND wr.user_id = #{userId} AND wr.create_time >= #{startTimeFrom} AND wr.create_time <= #{startTimeTo}
GROUP BY wr.category_id, wc.category_name ORDER BY totalCount DESC

WITH RECURSIVE target_depts AS ( SELECT id FROM dept WHERE id = #{deptId} UNION ALL SELECT d.id FROM dept d INNER JOIN target_depts td ON d.parent_id = td.id ) SELECT wr.user_id, u.real_name, wr.dept_id, d.dept_name, wr.category_id, wc.category_name, COUNT(DISTINCT wr.id) AS totalCount, COALESCE(SUM(wre.amount), 0) AS totalAmount FROM work_record wr JOIN user u ON wr.user_id = u.id LEFT JOIN dept d ON wr.dept_id = d.id LEFT JOIN work_category wc ON wr.category_id = wc.id LEFT JOIN work_record_expense wre ON wr.id = wre.work_record_id
wr.deleted = 0 AND wr.create_time >= #{endTimeFrom} AND wr.create_time <= #{endTimeTo}
AND wr.dept_id IN (SELECT id FROM target_depts)
AND wr.user_id = #{userId}
GROUP BY wr.user_id, u.real_name, wr.dept_id, d.dept_name, wr.category_id, wc.category_name ORDER BY d.dept_name, u.real_name, totalCount DESC

mapper.update:
UPDATE work_record
SET user_id = #{toUserId},
    dept_id = #{toDeptId}
WHERE id = #{id}
  AND user_id = #{fromUserId}
  AND deleted = 0
